<script setup>
import{computed,reactive,ref}from'vue';import{Head,Link}from'@inertiajs/vue3';import axios from'axios';
const props=defineProps({enrollments:Array,quizzes:Array});const items=ref(JSON.parse(JSON.stringify(props.quizzes||[])));const answers=reactive({});items.value.forEach(quiz=>quiz.questions.forEach(question=>answers[`${quiz.id}-${question.id}`]=[]));const answerFor=(quiz,question)=>answers[`${quiz.id}-${question.id}`]||(answers[`${quiz.id}-${question.id}`]=[]);const attemptsFor=(quiz)=>quiz.attempts||[];const remaining=(quiz)=>Math.max(0,quiz.max_attempts-attemptsFor(quiz).length);const submit=async(quiz)=>{const payload={};quiz.questions.forEach(q=>payload[q.id]=answerFor(quiz,q));const r=await axios.post(route('participant-portal.learning.quizzes.submit',quiz.id),{answers:payload});quiz.attempts.push(r.data.attempt);quiz.questions.forEach(q=>answers[`${quiz.id}-${q.id}`]=[]);};
</script>
<template><Head title="Kursquiz"/><main class="min-h-screen bg-sky-50 px-5 py-8"><div class="mx-auto max-w-5xl space-y-6"><header class="flex justify-between"><div><p class="text-xs font-semibold uppercase tracking-widest text-zbb">Matrix Teilnehmerportal</p><h1 class="text-2xl font-bold">Kursquiz</h1></div><div class="flex gap-2"><Link :href="route('participant-portal.learning.index')" class="rounded border bg-white px-4 py-2">Kurse</Link><Link :href="route('participant-portal.dashboard')" class="rounded border bg-white px-4 py-2">Dashboard</Link></div></header><article v-for="quiz in items" :key="quiz.id" class="rounded-2xl border bg-white p-6 shadow"><div class="flex justify-between gap-3"><div><h2 class="text-lg font-semibold">{{ quiz.title }}</h2><p class="text-sm text-gray-500">{{ quiz.course?.title }} · Bestehen ab {{ quiz.passing_percent }} %</p><p class="mt-2 text-sm text-gray-600">{{ quiz.description }}</p></div><span class="text-sm">Noch {{ remaining(quiz) }} Versuch(e)</span></div><div v-if="remaining(quiz)>0" class="mt-5 space-y-4"><fieldset v-for="(question,index) in quiz.questions" :key="question.id" class="rounded-xl border p-4"><legend class="px-2 font-semibold">{{ index+1 }}. {{ question.question }} ({{ question.points }} P.)</legend><label v-for="option in question.options" :key="option.id" class="mt-2 flex gap-2 text-sm"><input v-if="question.type==='multiple'" v-model="answers[`${quiz.id}-${question.id}`]" type="checkbox" :value="option.id"/><input v-else v-model="answers[`${quiz.id}-${question.id}`]" type="radio" :name="`q-${quiz.id}-${question.id}`" :value="[option.id]"/>{{ option.label }}</label></fieldset><button class="rounded bg-zbb px-4 py-2 text-white" @click="submit(quiz)">Versuch abgeben</button></div><div v-if="attemptsFor(quiz).length" class="mt-5"><h3 class="font-semibold">Ergebnisse</h3><p v-for="attempt in attemptsFor(quiz)" :key="attempt.id" class="mt-2 rounded p-3 text-sm" :class="attempt.passed?'bg-green-50 text-green-800':'bg-amber-50 text-amber-800'">Versuch {{ attempt.attempt_number }}: {{ attempt.percentage }} % · {{ attempt.passed?'bestanden':'nicht bestanden' }}</p></div></article><p v-if="!items.length" class="rounded-2xl border bg-white p-8 text-center text-gray-500">Keine veröffentlichten Quiz verfügbar.</p></div></main></template>
